import{_ as o,o as a,c as t,a3 as l}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Namespace clore::logging","description":"The clore::logging namespace provides a structured logging framework built on top of spdlog. Its core declarations include a LogProxy template struct used to create constant proxy objects such as trace, debug, info, warn, and err―each statically bound to a specific severity level for compile‑time log filtering. The central dispatcher function log accepts a severity enum and a message string, routing entries to the appropriate sinks. Additional utilities include stderr_logger for immediate output to standard error and cache_hit_rate for monitoring cache effectiveness. A global optional g_log_level allows runtime level overrides. Architecturally, clore::logging serves as the single point of contact for all logging in the codebase, abstracting away the underlying logging implementation and promoting consistent, type‑safe, and performance‑aware logging.","frontmatter":{"title":"Namespace clore::logging","description":"The clore::logging namespace provides a structured logging framework built on top of spdlog. Its core declarations include a LogProxy template struct used to create constant proxy objects such as trace, debug, info, warn, and err―each statically bound to a specific severity level for compile‑time log filtering. The central dispatcher function log accepts a severity enum and a message string, routing entries to the appropriate sinks. Additional utilities include stderr_logger for immediate output to standard error and cache_hit_rate for monitoring cache effectiveness. A global optional g_log_level allows runtime level overrides. Architecturally, clore::logging serves as the single point of contact for all logging in the codebase, abstracting away the underlying logging implementation and promoting consistent, type‑safe, and performance‑aware logging.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/namespaces/clore/logging/index.md","filePath":"en/clore/namespaces/clore/logging/index.md"}'),r={name:"clore/namespaces/clore/logging/index.md"};function i(n,e,s,g,c,d){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="namespace-clore-logging" tabindex="-1">Namespace <code>clore::logging</code> <a class="header-anchor" href="#namespace-clore-logging" aria-label="Permalink to &quot;Namespace `clore::logging`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>clore::logging</code> namespace provides a structured logging framework built on top of spdlog. Its core declarations include a <code>LogProxy</code> template struct used to create constant proxy objects such as <code>trace</code>, <code>debug</code>, <code>info</code>, <code>warn</code>, and <code>err</code>―each statically bound to a specific severity level for compile‑time log filtering. The central dispatcher function <code>log</code> accepts a severity enum and a message string, routing entries to the appropriate sinks. Additional utilities include <code>stderr_logger</code> for immediate output to standard error and <code>cache_hit_rate</code> for monitoring cache effectiveness. A global optional <code>g_log_level</code> allows runtime level overrides. Architecturally, <code>clore::logging</code> serves as the single point of contact for all logging in the codebase, abstracting away the underlying logging implementation and promoting consistent, type‑safe, and performance‑aware logging.</p><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-logging-logproxy" tabindex="-1"><code>clore::logging::LogProxy</code> <a class="header-anchor" href="#clore-logging-logproxy" aria-label="Permalink to &quot;`clore::logging::LogProxy`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:112</code></p><p>Definition: <code>support/logging.cppm:112</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>template parameter <code>Level</code> is a <code>spdlog::level::level_enum</code></li><li><code>operator()</code> overloads always call <code>log(Level, ...)</code></li><li>format-based overload requires <code>sizeof...(Args) &gt; 0</code></li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>operator()(std::string_view msg)</code></li><li><code>operator()(std::format_string&lt;Args...&gt; fmt, Args&amp;&amp;... args)</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to create type-safe log callables for different log levels</li><li>instances of <code>LogProxy</code> can be stored and passed as logging handlers, ensuring consistent level handling</li></ul><h4 id="member-functions" tabindex="-1">Member Functions <a class="header-anchor" href="#member-functions" aria-label="Permalink to &quot;Member Functions&quot;">​</a></h4><h5 id="clore-logging-logproxy-operator" tabindex="-1"><code>clore::logging::LogProxy::operator()</code> <a class="header-anchor" href="#clore-logging-logproxy-operator" aria-label="Permalink to &quot;`clore::logging::LogProxy::operator()`&quot;">​</a></h5><p>Declaration: <code>support/logging.cppm:119</code></p><p>Definition: <code>support/logging.cppm:119</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><h6 id="declaration" tabindex="-1">Declaration <a class="header-anchor" href="#declaration" aria-label="Permalink to &quot;Declaration&quot;">​</a></h6><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Args </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h5 id="clore-logging-logproxy-operator-1" tabindex="-1"><code>clore::logging::LogProxy::operator()</code> <a class="header-anchor" href="#clore-logging-logproxy-operator-1" aria-label="Permalink to &quot;`clore::logging::LogProxy::operator()`&quot;">​</a></h5><p>Declaration: <code>support/logging.cppm:113</code></p><p>Definition: <code>support/logging.cppm:113</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><h6 id="declaration-1" tabindex="-1">Declaration <a class="header-anchor" href="#declaration-1" aria-label="Permalink to &quot;Declaration&quot;">​</a></h6><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::string_view) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><h3 id="clore-logging-debug" tabindex="-1"><code>clore::logging::debug</code> <a class="header-anchor" href="#clore-logging-debug" aria-label="Permalink to &quot;`clore::logging::debug`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:125</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>A constant log proxy object for debug severity level, specialized with <code>spdlog::level::debug</code>. It provides a compile-time fixed log level for conditional logging.</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to log debug messages</li><li>invoked with format string and arguments</li></ul><h3 id="clore-logging-err" tabindex="-1"><code>clore::logging::err</code> <a class="header-anchor" href="#clore-logging-err" aria-label="Permalink to &quot;`clore::logging::err`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:128</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::err</code> is a <code>constexpr inline</code> variable of type <code>LogProxy&lt;spdlog::level::err&gt;</code>, serving as a constant proxy object for logging messages at the error severity level.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>logged via call <code>operator</code> with format string and arguments</li></ul><h3 id="clore-logging-g-log-level" tabindex="-1"><code>clore::logging::g_log_level</code> <a class="header-anchor" href="#clore-logging-g-log-level" aria-label="Permalink to &quot;`clore::logging::g_log_level`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:102</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>The variable <code>clore::logging::g_log_level</code> is a global <code>std::optional&lt;spdlog::level::level_enum&gt;</code> that provides an optional override for the log level used by the logging system.</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Read by <code>clore::logging::log</code> to check for a global log level override</li><li>Read by <code>clore::logging::stderr_logger</code> to check for a global log level override</li></ul><h3 id="clore-logging-info" tabindex="-1"><code>clore::logging::info</code> <a class="header-anchor" href="#clore-logging-info" aria-label="Permalink to &quot;`clore::logging::info`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:126</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>A constant inline proxy object for logging messages at the info severity level. It is declared as <code>constexpr inline LogProxy&lt;spdlog::level::info&gt; info</code> in the <code>clore::logging</code> namespace.</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used as a logging proxy for info level messages</li></ul><h3 id="clore-logging-trace" tabindex="-1"><code>clore::logging::trace</code> <a class="header-anchor" href="#clore-logging-trace" aria-label="Permalink to &quot;`clore::logging::trace`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:124</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>The variable <code>clore::logging::trace</code> is a <code>constexpr inline</code> object of type <code>LogProxy&lt;spdlog::level::trace&gt;</code>, declared in the <code>clore::logging</code> namespace.</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>emitting trace-level log messages</li></ul><h3 id="clore-logging-warn" tabindex="-1"><code>clore::logging::warn</code> <a class="header-anchor" href="#clore-logging-warn" aria-label="Permalink to &quot;`clore::logging::warn`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:127</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p><code>clore::logging::warn</code> is a <code>constexpr inline</code> variable of type <code>LogProxy&lt;spdlog::level::warn&gt;</code>, serving as a logging proxy for warning-level messages.</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used as a logging proxy for warning messages</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-logging-cache-hit-rate" tabindex="-1"><code>clore::logging::cache_hit_rate</code> <a class="header-anchor" href="#clore-logging-cache-hit-rate" aria-label="Permalink to &quot;`clore::logging::cache_hit_rate`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:138</code></p><p>Definition: <code>support/logging.cppm:138</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>Logs the cache hit rate for the operation or component identified by the given label. The caller provides two size parameters representing the number of cache hits and the total number of cache lookups (or equivalently, hits and misses). The function calculates the rate and records the result, typically at an informational logging level, allowing callers to monitor cache effectiveness without manually computing the ratio.</p><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to report cache hit/miss statistics</li><li>Typically used in performance monitoring sections</li></ul><h3 id="clore-logging-log" tabindex="-1"><code>clore::logging::log</code> <a class="header-anchor" href="#clore-logging-log" aria-label="Permalink to &quot;`clore::logging::log`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:104</code></p><p>Definition: <code>support/logging.cppm:104</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>Declaration: <a href="./functions/log">Declaration</a></p><p>The function <code>clore::logging::log</code> accepts a <code>spdlog::level::level_enum</code> indicating the severity of the log message and a <code>std::string_view</code> containing the message content. The caller is responsible for providing a valid log level and the message to be recorded; the function then dispatches the message to the appropriate logging sinks. This function serves as the central logging entry point and is invoked by higher‑level logging proxies such as <code>clore::logging::LogProxy::operator()</code>.</p><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>LogProxy::operator()(std::string_view)</code></li><li>used directly for logging with an explicit level</li></ul><h3 id="clore-logging-stderr-logger" tabindex="-1"><code>clore::logging::stderr_logger</code> <a class="header-anchor" href="#clore-logging-stderr-logger" aria-label="Permalink to &quot;`clore::logging::stderr_logger`&quot;">​</a></h3><p>Declaration: <code>support/logging.cppm:130</code></p><p>Definition: <code>support/logging.cppm:130</code></p><p>Implementation: <a href="./../../../modules/support/"><code>Module support</code></a></p><p>The function <code>clore::logging::stderr_logger</code> is a simple logging callable that writes a given message to the standard error stream. It accepts a single <code>std::string_view</code> argument containing the text to be logged and returns <code>void</code>. This function is intended for use as a lightweight, immediate-output logger, typically within the logging framework or as a default sink for situations where no other logging backend is configured. The caller is responsible for providing a valid string view; no formatting or additional context is added by this function.</p><h4 id="usage-patterns-9" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-9" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called at startup to configure stderr logging with a specific logger name</li><li>Used to switch the default logger to stderr output</li><li>Invocations optionally apply a previously stored log level</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore</a></li></ul>',90)])])}const u=o(r,[["render",i]]);export{h as __pageData,u as default};
